const items = $input.all();
if (!items.length) {
  throw new Error('xml-to-yolo 未返回任何结果');
}

const config = $node["Prepare Config"].json;
const convertedFragments = items.map((item) => ({
  dataset_dir: item.json.dataset_dir,
  converted_files: item.json.converted_files,
  total_boxes: item.json.total_boxes,
  classes: item.json.classes,
}));

return [{
  json: {
    input_dir: config.input_dir,
    converted_fragment_count: convertedFragments.length,
    converted_fragments: convertedFragments,
    clean_output_dir: config.clean_output_dir,
    aggregated_output_dir: config.aggregated_output_dir,
    images_dir_name: config.images_dir_name,
    labels_dir_name: config.labels_dir_name,
    backgrounds_dir_name: config.backgrounds_dir_name,
    overwrite: config.overwrite
  },
}];

