  json: {
    status: 'ok',
    input_dir: summary.input_dir,
    discovered_leaf_dirs: discover.total_leaf_dirs,
    cleaned_leaf_dirs: clean.processed_leaf_dirs,
    labeled_images: clean.labeled_images,
    background_images: clean.background_images,
    aggregated_images: aggregate.aggregated_images,
    aggregated_backgrounds: aggregate.aggregated_backgrounds,
    classes: aggregate.classes,
    clean_output_dir: clean.output_dir,
    dataset_output_dir: aggregate.output_dir,
    classes_file: aggregate.classes_file,
    manifest_path: aggregate.manifest_path
  },
}];
